import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface Category {
  name: string;
  itemCount: number;
  estimatedCost: number;
}

interface GroceryData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    categories: Category[];
    totalEstimatedCost: number;
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const groceryData = response.data as GroceryData;
  const { categories, totalEstimatedCost } = groceryData.data;
  const { primaryColor } = groceryData.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F8FAFC', mb: 1 }}>
              Grocery Categories
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Total Estimated Cost: ${totalEstimatedCost.toFixed(2)}
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: '#374151' }} />

          <PieChart
            height={200}
            series={[
              {
                data: categories.map((category) => ({
                  id: category.name,
                  value: category.estimatedCost,
                  fill: primaryColor,
                })),
                innerRadius: 0.5,
                outerRadius: 0.9,
              },
            ]}
            sx={{
              '& .MuiPieArc-root': {
                stroke: '#1E293B',
                strokeWidth: 1,
              },
            }}
          />

          <Stack spacing={1}>
            {categories.map((category) => (
              <Box key={category.name} sx={{ display: 'flex', justifyContent: 'space-between', color: '#F8FAFC' }}>
                <Typography variant="body2">{category.name}</Typography>
                <Typography variant="body2">${category.estimatedCost.toFixed(2)}</Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
